1	import {
2	  Injectable,
3	  NotFoundException,
4	  ForbiddenException,
5	  HttpException,
6	  HttpStatus,
7	} from '@nestjs/common';
8	import { InjectRepository } from '@nestjs/typeorm';
9	import { Repository, MoreThanOrEqual, SelectQueryBuilder } from 'typeorm';
10	import { Listing, ListingStatus } from '../database/entities/listing.entity';
11	import { SensitiveWord } from '../database/entities/sensitive-word.entity';
12	import { RateLimitEvent } from '../database/entities/rate-limit-event.entity';
13	import { AuditService } from '../audit/audit.service';
14	import { RiskService, RiskFlag } from '../risk/risk.service';
15	import { SearchListingsDto } from './dto/search-listings.dto';
16	import { CreateListingDto } from './dto/create-listing.dto';
17	import { UpdateListingDto } from './dto/update-listing.dto';
18	import { canViewListing } from './listing-visibility.policy';
19	import { RequestRiskContext } from '../common/risk/request-risk-context';
20	
21	const TYPO_MAP: Record<string, string> = {
22	  retreiver: 'retriever',
23	  retrever: 'retriever',
24	  retriver: 'retriever',
25	  goldern: 'golden',
26	  goldne: 'golden',
27	  chiwawa: 'chihuahua',
28	  chiwahua: 'chihuahua',
29	  dalmation: 'dalmatian',
30	  dalmatin: 'dalmatian',
31	  persain: 'persian',
32	  persion: 'persian',
33	  siamise: 'siamese',
34	  siamees: 'siamese',
35	  siberain: 'siberian',
36	  sibiren: 'siberian',
37	  buldog: 'bulldog',
38	  pudle: 'poodle',
39	  poddle: 'poodle',
40	  labrodor: 'labrador',
41	  labredor: 'labrador',
42	  rotweiler: 'rottweiler',
43	  rotwiler: 'rottweiler',
44	  shepard: 'shepherd',
45	  sheperd: 'shepherd',
46	  beagel: 'beagle',
47	  huskey: 'husky',
48	  mane: 'maine',
49	};
50	
51	const RATE_LIMIT_WINDOW_MS = 60 * 60 * 1000;
52	const RATE_LIMIT_MAX = 30;
53	
54	export interface PaginatedResult<T> {
55	  items: T[];
56	  total: number;
57	  page: number;
58	  limit: number;
59	  totalPages: number;
60	  fallback?: { similarBreed: T[]; trending: T[] };
61	}
62	
63	@Injectable()
64	export class ListingsService {
65	  constructor(
66	    @InjectRepository(Listing)
67	    private readonly listingRepo: Repository<Listing>,
68	    @InjectRepository(SensitiveWord)
69	    private readonly wordRepo: Repository<SensitiveWord>,
70	    @InjectRepository(RateLimitEvent)
71	    private readonly rateLimitRepo: Repository<RateLimitEvent>,
72	    private readonly auditService: AuditService,
73	    private readonly riskService: RiskService,
74	  ) {}
75	
76	  async search(query: SearchListingsDto): Promise<PaginatedResult<Listing>> {
77	    const page = Math.max(1, query.page ?? 1);
78	    const limit = Math.min(100, Math.max(1, query.limit ?? 20));
79	    const skip = (page - 1) * limit;
80	
81	    const correctedQ = query.q ? this.correctTypos(query.q) : undefined;
82	
83	    const qb = this.listingRepo
84	      .createQueryBuilder('l')
85	      .where('l.status = :status', { status: ListingStatus.ACTIVE })
86	      .andWhere('l.deletedAt IS NULL');
87	
88	    if (correctedQ) {
89	      qb.andWhere(
90	        '(l.title ILIKE :q OR l.description ILIKE :q OR l.breed ILIKE :q)',
91	        { q: `%${correctedQ}%` },
92	      );
93	    }
94	    if (query.breed) {
95	      qb.andWhere('LOWER(l.breed) = LOWER(:breed)', { breed: query.breed });
96	    }
97	    if (query.region) {
98	      qb.andWhere('LOWER(l.region) = LOWER(:region)', { region: query.region });
99	    }
100	    if (query.minAge !== undefined) {
101	      qb.andWhere('l.age >= :minAge', { minAge: query.minAge });
102	    }
103	    if (query.maxAge !== undefined) {
104	      qb.andWhere('l.age <= :maxAge', { maxAge: query.maxAge });
105	    }
106	    if (query.minPrice !== undefined) {
107	      qb.andWhere('l.priceUsd >= :minPrice', { minPrice: query.minPrice });
108	    }
109	    if (query.maxPrice !== undefined) {
110	      qb.andWhere('l.priceUsd <= :maxPrice', { maxPrice: query.maxPrice });
111	    }
112	    if (query.minRating !== undefined) {
113	      qb.andWhere('l.rating >= :minRating', { minRating: query.minRating });
114	    }
115	    if (query.maxRating !== undefined) {
116	      qb.andWhere('l.rating <= :maxRating', { maxRating: query.maxRating });
117	    }
118	    if (query.newArrivals) {
119	      const fourteenDaysAgo = new Date(Date.now() - 14 * 24 * 60 * 60 * 1000);
120	      qb.andWhere('l.createdAt >= :since', { since: fourteenDaysAgo });
121	    }
122	
123	    this.applySorting(qb, query.sort);
124	    qb.skip(skip).take(limit);
125	
126	    const [items, total] = await qb.getManyAndCount();
127	
128	    const result: PaginatedResult<Listing> = {
129	      items,
130	      total,
131	      page,
132	      limit,
133	      totalPages: Math.ceil(total / limit),
134	    };
135	
136	    if (total === 0) {
137	      result.fallback = await this.buildFallback(query.breed ?? correctedQ);
138	    }
139	
140	    return result;
141	  }
142	
143	  async suggest(q: string): Promise<string[]> {
144	    if (!q || q.length < 1) return [];
145	    const corrected = this.correctTypos(q);
146	    const pattern = `%${corrected}%`;
147	
148	    const breeds = await this.listingRepo
149	      .createQueryBuilder('l')
150	      .select('DISTINCT l.breed', 'value')
151	      .where('l.breed ILIKE :pattern', { pattern })
152	      .andWhere('l.status = :status', { status: ListingStatus.ACTIVE })
153	      .andWhere('l.deletedAt IS NULL')
154	      .limit(5)
155	      .getRawMany();
156	
157	    const titles = await this.listingRepo
158	      .createQueryBuilder('l')
159	      .select('l.title', 'value')
160	      .where('l.title ILIKE :pattern', { pattern })
161	      .andWhere('l.status = :status', { status: ListingStatus.ACTIVE })
162	      .andWhere('l.deletedAt IS NULL')
163	      .limit(5)
164	      .getRawMany();
165	
166	    const seen = new Set<string>();
167	    const results: string[] = [];
168	    for (const row of [...breeds, ...titles]) {
169	      const v = row.value as string;
170	      if (!seen.has(v.toLowerCase())) {
171	        seen.add(v.toLowerCase());
172	        results.push(v);
173	      }
174	      if (results.length >= 10) break;
175	    }
176	    return results;
177	  }
178	
179	  async findOne(
180	    id: string,
181	    requesterRole?: string,
182	    requesterId?: string,
183	  ): Promise<Listing> {
184	    const listing = await this.listingRepo.findOne({
185	      where: { id },
186	      relations: ['vendor'],
187	    });
188	    if (!listing || !canViewListing(listing, requesterRole, requesterId)) {
189	      throw new NotFoundException('Listing not found');
190	    }
191	    return listing;
192	  }
193	
194	  async create(
195	    vendorId: string,
196	    dto: CreateListingDto,
197	    riskCtx: RequestRiskContext = { ip: undefined, deviceFingerprint: undefined },
198	  ): Promise<{ listing: Listing; flagged: boolean; reason?: string; duplicateWarning?: string }> {
199	    await this.enforceRateLimit(vendorId);
200	
201	    const duplicateWarning = await this.detectDuplicate(vendorId, dto.title);
202	    const { flagged } = await this.checkSensitiveWords(dto.title, dto.description);
203	
204	    // Risk assessment runs BEFORE the save so flags can influence listing status
205	    const riskFlags = await this.riskService.assessListingCreation(
206	      vendorId,
207	      dto.breed,
208	      riskCtx.deviceFingerprint,
209	      riskCtx.ip,
210	    );
211	
212	    const shouldReview = flagged || riskFlags.length > 0;
213	
214	    const listing = this.listingRepo.create({
215	      ...dto,
216	      vendorId,
217	      photos: dto.photos ?? [],
218	      status: shouldReview ? ListingStatus.PENDING_REVIEW : ListingStatus.ACTIVE,
219	      sensitiveWordFlagged: flagged,
220	    });
221	    const saved = await this.listingRepo.save(listing);
222	
223	    await this.rateLimitRepo.save(
224	      this.rateLimitRepo.create({ userId: vendorId, action: 'create_listing' }),
225	    );
226	
227	    await this.auditService.log({
228	      action: 'listing.create',
229	      actorId: vendorId,
230	      entityType: 'listing',
231	      entityId: saved.id,
232	      after: { id: saved.id, title: saved.title, status: saved.status } as unknown as Record<string, unknown>,
233	    });
234	
235	    const result: { listing: Listing; flagged: boolean; reason?: string; duplicateWarning?: string; riskFlags?: RiskFlag[] } = {
236	      listing: saved,
237	      flagged: shouldReview,
238	    };
239	    if (shouldReview) {
240	      result.reason = flagged
241	        ? 'Review required: prohibited terms detected'
242	        : 'Review required: risk signals detected';
243	    }
244	    if (duplicateWarning) result.duplicateWarning = duplicateWarning;
245	    if (riskFlags.length > 0) result.riskFlags = riskFlags;
246	    return result;
247	  }
248	
249	  async update(
250	    id: string,
251	    userId: string,
252	    userRole: string,
253	    dto: UpdateListingDto,
254	  ): Promise<{ listing: Listing; flagged: boolean; reason?: string }> {
255	    const listing = await this.listingRepo.findOne({ where: { id } });
256	    if (!listing) throw new NotFoundException('Listing not found');
257	    if (userRole !== 'admin' && listing.vendorId !== userId) {
258	      throw new ForbiddenException('You can only update your own listings');
259	    }
260	
261	    const before = { ...listing } as unknown as Record<string, unknown>;
262	    const newTitle = dto.title ?? listing.title;
263	    const newDesc = dto.description ?? listing.description;
264	    const { flagged } = await this.checkSensitiveWords(newTitle, newDesc);
265	
266	    Object.assign(listing, dto);
267	    if (dto.photos !== undefined) listing.photos = dto.photos;
268	    listing.sensitiveWordFlagged = flagged;
269	    if (flagged) listing.status = ListingStatus.PENDING_REVIEW;
270	
271	    const saved = await this.listingRepo.save(listing);
272	
273	    await this.auditService.log({
274	      action: 'listing.update',
275	      actorId: userId,
276	      entityType: 'listing',
277	      entityId: id,
278	      before,
279	      after: { id: saved.id, title: saved.title, status: saved.status } as unknown as Record<string, unknown>,
280	    });
281	
282	    const result: { listing: Listing; flagged: boolean; reason?: string } = { listing: saved, flagged };
283	    if (flagged) result.reason = 'Review required: prohibited terms detected';
284	    return result;
285	  }
286	
287	  async softDelete(id: string, userId: string, userRole: string): Promise<void> {
288	    const listing = await this.listingRepo.findOne({ where: { id } });
289	    if (!listing) throw new NotFoundException('Listing not found');
290	    if (userRole !== 'admin' && listing.vendorId !== userId) {
291	      throw new ForbiddenException('You can only delete your own listings');
292	    }
293	
294	    await this.listingRepo.softDelete(id);
295	
296	    await this.auditService.log({
297	      action: 'listing.delete',
298	      actorId: userId,
299	      entityType: 'listing',
300	      entityId: id,
301	      before: { id: listing.id, title: listing.title } as unknown as Record<string, unknown>,
302	    });
303	  }
304	
305	  private correctTypos(input: string): string {
306	    return input
307	      .split(/\s+/)
308	      .map((word) => TYPO_MAP[word.toLowerCase()] ?? word)
309	      .join(' ');
310	  }
311	
312	  private applySorting(qb: SelectQueryBuilder<Listing>, sort?: string): void {
313	    switch (sort) {
314	      case 'price_asc':
315	        qb.orderBy('l.priceUsd', 'ASC');
316	        break;
317	      case 'price_desc':
318	        qb.orderBy('l.priceUsd', 'DESC');
319	        break;
320	      case 'rating_desc':
321	        qb.orderBy('l.rating', 'DESC');
322	        break;
323	      case 'newest':
324	      default:
325	        qb.orderBy('l.createdAt', 'DESC');
326	        break;
327	    }
328	  }
329	
330	  private async buildFallback(
331	    breedHint?: string,
332	  ): Promise<{ similarBreed: Listing[]; trending: Listing[] }> {
333	    let similarBreed: Listing[] = [];
334	    if (breedHint) {
335	      similarBreed = await this.listingRepo
336	        .createQueryBuilder('l')
337	        .where('l.status = :status', { status: ListingStatus.ACTIVE })
338	        .andWhere('l.deletedAt IS NULL')
339	        .andWhere('l.breed ILIKE :breed', { breed: `%${breedHint}%` })
340	        .orderBy('l.rating', 'DESC')
341	        .limit(5)
342	        .getMany();
343	    }
344	
345	    const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
346	    const trending = await this.listingRepo
347	      .createQueryBuilder('l')
348	      .where('l.status = :status', { status: ListingStatus.ACTIVE })
349	      .andWhere('l.deletedAt IS NULL')
350	      .andWhere('l.createdAt >= :since', { since: sevenDaysAgo })
351	      .orderBy('l.rating', 'DESC')
352	      .limit(5)
353	      .getMany();
354	
355	    return { similarBreed, trending };
356	  }
357	
358	  private async checkSensitiveWords(
359	    title: string,
360	    description: string,
361	  ): Promise<{ flagged: boolean; matchedWords: string[] }> {
362	    const words = await this.wordRepo.find();
363	    const combined = `${title} ${description}`.toLowerCase();
364	    const matched = words.filter((sw) => combined.includes(sw.word.toLowerCase()));
365	    return { flagged: matched.length > 0, matchedWords: matched.map((w) => w.word) };
366	  }
367	
368	  private async enforceRateLimit(vendorId: string): Promise<void> {
369	    const windowStart = new Date(Date.now() - RATE_LIMIT_WINDOW_MS);
370	    const count = await this.rateLimitRepo.count({
371	      where: {
372	        userId: vendorId,
373	        action: 'create_listing',
374	        createdAt: MoreThanOrEqual(windowStart),
375	      },
376	    });
377	    if (count >= RATE_LIMIT_MAX) {
378	      throw new HttpException('Rate limit exceeded: max 30 listings per hour', HttpStatus.TOO_MANY_REQUESTS);
379	    }
380	  }
381	
382	  private async detectDuplicate(vendorId: string, title: string): Promise<string | undefined> {
383	    const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);
384	    const recent = await this.listingRepo
385	      .createQueryBuilder('l')
386	      .where('l.vendorId = :vendorId', { vendorId })
387	      .andWhere('l.createdAt >= :since', { since: oneDayAgo })
388	      .andWhere('l.deletedAt IS NULL')
389	      .getMany();
390	
391	    const inputTokens = this.tokenize(title);
392	    if (inputTokens.length === 0) return undefined;
393	
394	    for (const listing of recent) {
395	      const existingTokens = this.tokenize(listing.title);
396	      if (existingTokens.length === 0) continue;
397	      const intersection = inputTokens.filter((t) => existingTokens.includes(t));
398	      const overlap = intersection.length / Math.max(inputTokens.length, existingTokens.length);
399	      if (overlap >= 0.8) {
400	        return `Near-duplicate detected: similar to "${listing.title}" (${Math.round(overlap * 100)}% overlap)`;
401	      }
402	    }
403	    return undefined;
404	  }
405	
406	  private tokenize(text: string): string[] {
407	    return text.toLowerCase().split(/\s+/).filter((w) => w.length > 2);
408	  }
409	}
410	
