1	import {
2	  Controller,
3	  Get,
4	  Post,
5	  Put,
6	  Delete,
7	  Param,
8	  Body,
9	  Query,
10	  Req,
11	  UseGuards,
12	  ParseUUIDPipe,
13	  HttpCode,
14	  HttpStatus,
15	} from '@nestjs/common';
16	import { Request } from 'express';
17	import { ListingsService } from './listings.service';
18	import { SearchListingsDto, SuggestDto } from './dto/search-listings.dto';
19	import { CreateListingDto } from './dto/create-listing.dto';
20	import { UpdateListingDto } from './dto/update-listing.dto';
21	import { JwtAuthGuard, JwtPayload } from '../common/guards/jwt-auth.guard';
22	import { OptionalJwtAuthGuard } from '../common/guards/optional-jwt-auth.guard';
23	import { RolesGuard } from '../common/guards/roles.guard';
24	import { Roles } from '../common/decorators/roles.decorator';
25	import { extractRiskContext } from '../common/risk/request-risk-context';
26	
27	@Controller('listings')
28	export class ListingsController {
29	  constructor(private readonly listingsService: ListingsService) {}
30	
31	  @Get()
32	  search(@Query() query: SearchListingsDto) {
33	    return this.listingsService.search(query);
34	  }
35	
36	  @Get('suggest')
37	  suggest(@Query() query: SuggestDto) {
38	    return this.listingsService.suggest(query.q ?? '');
39	  }
40	
41	  @Get(':id')
42	  @UseGuards(OptionalJwtAuthGuard)
43	  findOne(@Param('id', ParseUUIDPipe) id: string, @Req() req: Request) {
44	    const user = (req as Request & { user?: JwtPayload }).user;
45	    return this.listingsService.findOne(id, user?.role, user?.sub);
46	  }
47	
48	  @Post()
49	  @UseGuards(JwtAuthGuard, RolesGuard)
50	  @Roles('vendor', 'admin')
51	  create(@Body() dto: CreateListingDto, @Req() req: Request) {
52	    const user = (req as Request & { user: JwtPayload }).user;
53	    return this.listingsService.create(user.sub, dto, extractRiskContext(req));
54	  }
55	
56	  @Put(':id')
57	  @UseGuards(JwtAuthGuard, RolesGuard)
58	  @Roles('vendor', 'admin')
59	  update(
60	    @Param('id', ParseUUIDPipe) id: string,
61	    @Body() dto: UpdateListingDto,
62	    @Req() req: Request,
63	  ) {
64	    const user = (req as Request & { user: JwtPayload }).user;
65	    return this.listingsService.update(id, user.sub, user.role, dto);
66	  }
67	
68	  @Delete(':id')
69	  @HttpCode(HttpStatus.OK)
70	  @UseGuards(JwtAuthGuard, RolesGuard)
71	  @Roles('vendor', 'admin')
72	  remove(
73	    @Param('id', ParseUUIDPipe) id: string,
74	    @Req() req: Request,
75	  ) {
76	    const user = (req as Request & { user: JwtPayload }).user;
77	    return this.listingsService.softDelete(id, user.sub, user.role);
78	  }
79	}
