1	/**
2	 * listing-access.spec.ts
3	 *
4	 * Risk: listings in pending_review status are directly retrievable by
5	 * non-owners via GET /listings/:id, bypassing the visibility policy.
6	 *
7	 * Covers:
8	 *   - anonymous caller → 404 for pending listing
9	 *   - shopper → 404
10	 *   - non-owner vendor → 404
11	 *   - owner vendor → 200
12	 *   - admin → 200
13	 *   - ACTIVE listing is visible to everyone (control)
14	 */
15	import * as request from 'supertest';
16	import { createTestApp, makeToken, TestContext } from './test-utils';
17	import { User } from '../database/entities/user.entity';
18	import { Listing, ListingStatus } from '../database/entities/listing.entity';
19	import { createTestUser, createTestListing, cleanupAll } from './test-fixtures';
20	
21	describe('Pending-review listing direct retrieval denied to non-owners', () => {
22	  let ctx: TestContext;
23	  let ownerVendor: User;
24	  let otherVendor: User;
25	  let shopper: User;
26	  let adminUser: User;
27	  let pendingListing: Listing;
28	  let activeListing: Listing;
29	
30	  beforeAll(async () => {
31	    ctx = await createTestApp();
32	    const ds = ctx.dataSource;
33	
34	    ownerVendor = await createTestUser(ds, 'vendor');
35	    otherVendor = await createTestUser(ds, 'vendor');
36	    shopper = await createTestUser(ds, 'shopper');
37	    adminUser = await createTestUser(ds, 'admin');
38	
39	    pendingListing = await createTestListing(ds, ownerVendor.id, ListingStatus.PENDING_REVIEW);
40	    activeListing = await createTestListing(ds, ownerVendor.id, ListingStatus.ACTIVE);
41	  }, 30000);
42	
43	  afterAll(async () => {
44	    await cleanupAll(ctx.dataSource, [
45	      { entity: Listing, ids: [pendingListing?.id, activeListing?.id].filter(Boolean) as string[] },
46	      { entity: User, ids: [ownerVendor?.id, otherVendor?.id, shopper?.id, adminUser?.id].filter(Boolean) as string[] },
47	    ]);
48	    await ctx.app.close();
49	  });
50	
51	  // ── Denial cases ────────────────────────────────────────────────────────────
52	
53	  it('anonymous caller cannot retrieve a pending_review listing (404)', async () => {
54	    const res = await request(ctx.app.getHttpServer())
55	      .get(`/api/listings/${pendingListing.id}`);
56	    // No auth guard on this endpoint — visibility is enforced inside the service
57	    expect(res.body.code).toBe(404);
58	  });
59	
60	  it('shopper cannot retrieve a pending_review listing (404)', async () => {
61	    const token = makeToken(ctx.jwtService, shopper.id, 'shopper', shopper.username);
62	    const res = await request(ctx.app.getHttpServer())
63	      .get(`/api/listings/${pendingListing.id}`)
64	      .set('Authorization', `Bearer ${token}`);
65	    expect(res.body.code).toBe(404);
