8	@Injectable()
9	export class UserSanitizerService {
10	  constructor(private readonly encryption: EncryptionService) {}
11	
12	  /**
13	   * Returns a sanitized UserView.
14	   * Default (non-privileged): email masked as '***', deviceFingerprint and lastIp omitted.
15	   * Privileged (admin): email and deviceFingerprint decrypted, lastIp included.
16	   */
17	  sanitize(user: Partial<User>, requesterRole: string): UserView {
18	    const base: UserView = {
19	      id: user.id!,
20	      username: user.username!,
21	      email: '***',
22	      role: user.role!,
23	      isActive: user.isActive ?? true,
24	      createdAt: user.createdAt!,
25	      updatedAt: user.updatedAt!,
26	    };
27	
28	    if (PRIVILEGED_ROLES.has(requesterRole)) {
29	      return {
30	        ...base,
31	        email: user.email ? this.encryption.decrypt(user.email) : '***',
32	        deviceFingerprint: user.deviceFingerprint
33	          ? this.encryption.decrypt(user.deviceFingerprint)
34	          : user.deviceFingerprint ?? null,
35	        lastIp: user.lastIp ?? null,
36	      };
37	    }
38	
39	    return base;
40	  }
