59	    const limit = Math.min(SEARCH_MAX_LIMIT, Math.max(1, filters.limit ?? SEARCH_DEFAULT_LIMIT));
60	
61	    const qb = this.convRepo
62	      .createQueryBuilder('c')
63	      .leftJoinAndSelect('c.listing', 'listing');
64	
65	    if (role === 'vendor') {
66	      qb.where('c.vendorId = :userId', { userId });
67	    } else if (role === 'shopper') {
68	      qb.where(':userId = ANY(c.shopperIds)', { userId });
69	    }
70	
71	    if (filters.archived !== undefined) {
72	      qb.andWhere('c.isArchived = :archived', { archived: filters.archived });
73	    }
74	    if (filters.listingId) {
75	      qb.andWhere('c.listingId = :listingId', { listingId: filters.listingId });
76	    }
77	    if (filters.keyword) {
78	      // Primary: match any message content in the conversation.
79	      // Secondary: match the listing title.
