10	@Catch()
11	export class HttpExceptionFilter implements ExceptionFilter {
12	  catch(exception: unknown, host: ArgumentsHost): void {
13	    const ctx = host.switchToHttp();
14	    const response = ctx.getResponse<Response>();
15	
16	    let status = HttpStatus.INTERNAL_SERVER_ERROR;
17	    let msg = 'Internal server error';
18	
19	    if (exception instanceof HttpException) {
20	      status = exception.getStatus();
21	      const res = exception.getResponse();
22	      if (typeof res === 'string') {
23	        msg = res;
24	      } else if (typeof res === 'object' && res !== null) {
25	        const resObj = res as Record<string, unknown>;
26	        if (Array.isArray(resObj['message'])) {
27	          msg = (resObj['message'] as string[]).join('; ');
28	        } else if (typeof resObj['message'] === 'string') {
29	          msg = resObj['message'];
30	        }
31	      }
32	    } else if (exception instanceof Error) {
33	      msg = exception.message;
34	    }
35	
36	    response.status(status).json({
37	      code: status,
38	      msg,
39	      timestamp: new Date().toISOString(),
40	    });
41	  }
42	}
