1	import { Injectable, OnModuleInit, OnModuleDestroy } from '@nestjs/common';
2	import { InjectRepository } from '@nestjs/typeorm';
3	import { Repository, IsNull, LessThan } from 'typeorm';
4	import * as crypto from 'crypto';
5	import { AuditLog } from '../database/entities/audit-log.entity';
6	import { User } from '../database/entities/user.entity';
7	import {
8	  RETENTION_BATCH_SIZE,
9	  ARCHIVE_REASON,
10	  retentionCutoff,
11	} from './audit-retention.policy';
12	
13	export interface AuditLogInput {
14	  action: string;
15	  actorId: string;
16	  entityType: string;
17	  entityId?: string;
18	  before?: Record<string, unknown> | null;
19	  after?: Record<string, unknown> | null;
20	  deviceFingerprint?: string;
21	  ip?: string;
22	}
23	
24	export interface RetentionRunResult {
25	  dryRun: boolean;
26	  processed: number;
27	  archived: number;
28	  cutoff: Date;
29	}
30	
31	export interface AuditFilters {
32	  actorId?: string;
33	  entityType?: string;
34	  action?: string;
35	  startDate?: string;
36	  endDate?: string;
37	  keyword?: string;
38	  page?: number;
39	  limit?: number;
40	}
41	
42	const RETENTION_INTERVAL_MS = 24 * 60 * 60 * 1000; // daily
43	
44	@Injectable()
45	export class AuditService implements OnModuleInit, OnModuleDestroy {
46	  private retentionTimer: NodeJS.Timeout | null = null;
47	
48	  constructor(
49	    @InjectRepository(AuditLog)
50	    private readonly auditRepo: Repository<AuditLog>,
51	  ) {}
52	
53	  onModuleInit(): void {
54	    this.retentionTimer = setInterval(() => {
55	      this.runRetentionJob(false).catch(() => {
56	        // swallow — retention failures must not crash the service
57	      });
58	    }, RETENTION_INTERVAL_MS);
59	  }
60	
61	  onModuleDestroy(): void {
62	    if (this.retentionTimer) {
63	      clearInterval(this.retentionTimer);
64	      this.retentionTimer = null;
65	    }
66	  }
67	
68	  async log(input: AuditLogInput): Promise<AuditLog> {
69	    const latest = await this.auditRepo.findOne({
70	      where: {},
71	      order: { createdAt: 'DESC' },
72	    });
73	
74	    const prevHash = latest?.hash ?? null;
75	    const ts = new Date().toISOString();
76	    const hashPayload = (prevHash ?? '') + JSON.stringify({
77	      action: input.action,
78	      actorId: input.actorId,
79	      entityType: input.entityType,
80	      entityId: input.entityId ?? null,
81	      before: input.before ?? null,
82	      after: input.after ?? null,
83	      ts,
84	    });
85	    const hash = crypto.createHash('sha256').update(hashPayload).digest('hex');
86	
87	    const entry = this.auditRepo.create({
88	      action: input.action,
89	      actorId: input.actorId,
90	      entityType: input.entityType,
91	      entityId: input.entityId ?? null,
92	      before: input.before ?? null,
93	      after: input.after ?? null,
94	      deviceFingerprint: input.deviceFingerprint ?? null,
95	      ip: input.ip ?? null,
96	      hash,
97	      prevHash,
98	      createdAt: new Date(ts),
99	    });
100	
101	    return this.auditRepo.save(entry);
102	  }
103	
104	  async findAll(
105	    page = 1,
106	    limit = 50,
107	  ): Promise<{ items: AuditLog[]; total: number }> {
108	    const [items, total] = await this.auditRepo.findAndCount({
109	      order: { createdAt: 'DESC' },
110	      skip: (page - 1) * limit,
111	      take: limit,
112	    });
113	    return { items, total };
114	  }
115	
116	  async findAllFiltered(
117	    filters: AuditFilters,
118	  ): Promise<{ items: (AuditLog & { actorUsername?: string })[]; total: number }> {
119	    const page = Math.max(1, filters.page ?? 1);
120	    const limit = Math.min(200, Math.max(1, filters.limit ?? 50));
121	
122	    const qb = this.auditRepo
123	      .createQueryBuilder('a')
124	      .orderBy('a.createdAt', 'DESC');
125	
126	    if (filters.actorId) {
127	      qb.andWhere('a.actorId = :actorId', { actorId: filters.actorId });
128	    }
129	    if (filters.entityType) {
130	      qb.andWhere('a.entityType = :entityType', { entityType: filters.entityType });
131	    }
132	    if (filters.action) {
133	      qb.andWhere('a.action ILIKE :action', { action: `%${filters.action}%` });
134	    }
135	    if (filters.startDate) {
136	      qb.andWhere('a.createdAt >= :startDate', { startDate: new Date(filters.startDate) });
137	    }
138	    if (filters.endDate) {
139	      qb.andWhere('a.createdAt <= :endDate', { endDate: new Date(filters.endDate) });
140	    }
141	    if (filters.keyword) {
142	      qb.andWhere(
143	        '(CAST(a.before AS text) ILIKE :kw OR CAST(a.after AS text) ILIKE :kw)',
144	        { kw: `%${filters.keyword}%` },
145	      );
146	    }
147	
148	    qb.skip((page - 1) * limit).take(limit);
149	
150	    const [items, total] = await qb.getManyAndCount();
151	
152	    const actorIds = [...new Set(items.map((i: AuditLog) => i.actorId).filter(Boolean))];
153	    const userMap: Record<string, string> = {};
154	    if (actorIds.length > 0) {
155	      const userRepo = this.auditRepo.manager.getRepository(User);
156	      const users = await userRepo
157	        .createQueryBuilder('u')
158	        .where('u.id IN (:...ids)', { ids: actorIds })
159	        .getMany();
160	      for (const u of users) {
161	        userMap[u.id] = u.username;
162	      }
163	    }
164	
165	    const enriched = items.map((item: AuditLog) => ({
166	      ...item,
167	      actorUsername: userMap[item.actorId] ?? 'unknown',
168	    }));
169	
170	    return { items: enriched, total };
171	  }
172	
173	  /**
174	   * Archives audit records older than the 7-year retention boundary.
175	   *
176	   * Tombstone strategy: `deviceFingerprint` and `ip` (PII) are cleared; all
177	   * fields that form the SHA-256 hash payload (action, actorId, entityType,
178	   * entityId, before, after, ts/createdAt) are untouched so the chain stays
179	   * fully verifiable after archival.
180	   *
181	   * Idempotent: the WHERE clause includes `archivedAt IS NULL`, so re-running
182	   * the job never double-processes a record.
183	   *
184	   * @param dryRun When true, counts eligible records without modifying them.
185	   */
186	  async runRetentionJob(dryRun = false): Promise<RetentionRunResult> {
187	    const cutoff = retentionCutoff();
188	    let processed = 0;
189	    let archived = 0;
190	    let offset = 0;
191	
192	    while (true) {
193	      const batch = await this.auditRepo.find({
194	        where: {
195	          archivedAt: IsNull(),
196	          createdAt: LessThan(cutoff),
197	        },
198	        order: { createdAt: 'ASC' },
199	        take: RETENTION_BATCH_SIZE,
200	        // In live mode the processed records are marked archivedAt IS NOT NULL,
201	        // so the query self-shrinks and offset stays 0.  In dry-run mode
202	        // nothing changes, so we must page forward manually.
203	        skip: dryRun ? offset : 0,
204	      });
205	
206	      if (batch.length === 0) break;
207	
208	      processed += batch.length;
209	
210	      if (!dryRun) {
211	        const ids = batch.map((r: AuditLog) => r.id);
212	        const now = new Date();
213	        await this.auditRepo
214	          .createQueryBuilder()
215	          .update(AuditLog)
216	          .set({ deviceFingerprint: null, ip: null, archivedAt: now, archiveReason: ARCHIVE_REASON })
217	          .whereInIds(ids)
218	          .andWhere('archivedAt IS NULL') // belt-and-suspenders idempotency guard
219	          .execute();
220	        archived += batch.length;
221	      } else {
222	        archived += batch.length;
223	        offset += RETENTION_BATCH_SIZE;
224	      }
225	
226	      if (batch.length < RETENTION_BATCH_SIZE) break;
227	    }
228	
229	    return { dryRun, processed, archived, cutoff };
230	  }
231	
232	  async verifyEntry(id: string): Promise<{ valid: boolean; entry: AuditLog }> {
233	    const entry = await this.auditRepo.findOne({ where: { id } });
234	    if (!entry) {
235	      throw new Error('Audit entry not found');
236	    }
237	
238	    const recomputedPayload = (entry.prevHash ?? '') + JSON.stringify({
239	      action: entry.action,
240	      actorId: entry.actorId,
241	      entityType: entry.entityType,
242	      entityId: entry.entityId ?? null,
243	      before: entry.before ?? null,
244	      after: entry.after ?? null,
245	      ts: entry.createdAt.toISOString(),
246	    });
247	    const recomputedHash = crypto
248	      .createHash('sha256')
249	      .update(recomputedPayload)
250	      .digest('hex');
251	
252	    return {
253	      valid: recomputedHash === entry.hash,
254	      entry,
255	    };
256	  }
257	}
