1	export const RETENTION_YEARS = 7;
2	export const RETENTION_BATCH_SIZE = 500;
3	export const ARCHIVE_REASON = '7-year retention policy: PII cleared, hash chain intact';
4	
5	export function retentionCutoff(now?: Date): Date {
6	  const d = now ? new Date(now.getTime()) : new Date();
7	  d.setFullYear(d.getFullYear() - RETENTION_YEARS);
8	  return d;
9	}
10	
11	export function isEligibleForArchival(
12	  record: { createdAt: Date; archivedAt: Date | null },
13	  cutoff: Date,
14	): boolean {
15	  return record.archivedAt === null && record.createdAt < cutoff;
16	}
