35	@Injectable()
36	export class SettlementsService {
37	  constructor(
38	    @InjectRepository(Settlement)
39	    private readonly settlementRepo: Repository<Settlement>,
40	    @InjectRepository(Listing)
41	    private readonly listingRepo: Repository<Listing>,
42	    @InjectRepository(User)
