69	  async findOne(id: string, userId: string, role: string): Promise<{
70	    settlement: Settlement;
71	    variance: { expected: number; actual: number; variance: number; variancePercent: number };
72	  }> {
73	    const settlement = await this.settlementRepo.findOne({ where: { id } });
74	    if (!settlement) throw new NotFoundException('Settlement not found');
75	    if (role === 'vendor' && settlement.vendorId !== userId) {
76	      throw new ForbiddenException('Access denied to this settlement');
77	    }
78	
79	    const expected = Number(settlement.totalCharges);
80	    const actual = expected;
81	    const variance = actual - expected;
82	    const variancePercent = expected > 0 ? (variance / expected) * 100 : 0;
83	
84	    return {
85	      settlement,
86	      variance: {
87	        expected: round(expected),
88	        actual: round(actual),
89	        variance: round(variance),
90	        variancePercent: round(variancePercent),
91	      },
92	    };
93	  }
