     1	import { ForbiddenException, BadRequestException } from '@nestjs/common';
     2	import { Settlement, SettlementStatus } from '../database/entities/settlement.entity';
     3	
     4	/**
     5	 * Separation-of-duties policy for settlement approvals.
     6	 *
     7	 * Step 1 – ops_reviewer only; settlement must be PENDING.
     8	 * Step 2 – finance_admin only; settlement must be REVIEWER_APPROVED;
     9	 *           the step-2 actor MUST differ from the step-1 actor.
    10	 *
    11	 * Admin is intentionally excluded from both steps: financial dual-control
    12	 * must be technically enforced, not just documented.
    13	 */
    14	
    15	export function validateStep1Approval(
    16	  settlement: Pick<Settlement, 'status' | 'reviewerApprovedBy'>,
    17	  actorRole: string,
    18	): void {
    19	  if (actorRole !== 'ops_reviewer') {
    20	    throw new ForbiddenException('Step 1 approval requires ops_reviewer role');
    21	  }
    22	  if (settlement.status !== SettlementStatus.PENDING) {
    23	    throw new BadRequestException(
    24	      `Settlement must be in '${SettlementStatus.PENDING}' status for step 1 (current: ${settlement.status})`,
    25	    );
    26	  }
    27	}
    28	
    29	export function validateStep2Approval(
    30	  settlement: Pick<Settlement, 'status' | 'reviewerApprovedBy'>,
    31	  actorId: string,
    32	  actorRole: string,
    33	): void {
    34	  if (actorRole !== 'finance_admin') {
    35	    throw new ForbiddenException('Step 2 approval requires finance_admin role');
    36	  }
    37	  if (settlement.status !== SettlementStatus.REVIEWER_APPROVED) {
    38	    throw new BadRequestException(
    39	      `Settlement must be in '${SettlementStatus.REVIEWER_APPROVED}' status for step 2 (current: ${settlement.status})`,
    40	    );
    41	  }
    42	  if (settlement.reviewerApprovedBy && settlement.reviewerApprovedBy === actorId) {
    43	    throw new ForbiddenException(
    44	      'Separation of duties: step 2 approver must be a different user than step 1 approver',
    45	    );
    46	  }
    47	}
