     7	function pendingSettlement() {
     8	  return { status: SettlementStatus.PENDING, reviewerApprovedBy: null as string | null };
     9	}
    10	
    11	function reviewerApprovedSettlement(step1UserId = 'ops-user-1') {
    12	  return { status: SettlementStatus.REVIEWER_APPROVED, reviewerApprovedBy: step1UserId };
    13	}
    14	
    15	// ── validateStep1Approval ─────────────────────────────────────────────────────
    16	
    17	describe('validateStep1Approval', () => {
    18	  describe('role checks', () => {
    19	    it('ops_reviewer role is allowed', () => {
    20	      expect(() => validateStep1Approval(pendingSettlement(), 'ops_reviewer')).not.toThrow();
    21	    });
    22	
    23	    it('finance_admin role is rejected', () => {
    24	      expect(() => validateStep1Approval(pendingSettlement(), 'finance_admin'))
    25	        .toThrow(ForbiddenException);
    26	    });
    27	
    28	    it('admin role is rejected — no bypass', () => {
    29	      expect(() => validateStep1Approval(pendingSettlement(), 'admin'))
    30	        .toThrow(ForbiddenException);
    31	    });
    32	
    33	    it('vendor role is rejected', () => {
    34	      expect(() => validateStep1Approval(pendingSettlement(), 'vendor'))
    35	        .toThrow(ForbiddenException);
    36	    });
    37	
    38	    it('shopper role is rejected', () => {
    39	      expect(() => validateStep1Approval(pendingSettlement(), 'shopper'))
    40	        .toThrow(ForbiddenException);
    41	    });
    42	  });
    43	
    44	  describe('state checks', () => {
    45	    it('PENDING status allows step 1', () => {
    46	      expect(() => validateStep1Approval({ status: SettlementStatus.PENDING, reviewerApprovedBy: null }, 'ops_reviewer'))
    47	        .not.toThrow();
    48	    });
    49	
    50	    it('REVIEWER_APPROVED status rejects step 1 (already done)', () => {
    51	      expect(() => validateStep1Approval(
    52	        { status: SettlementStatus.REVIEWER_APPROVED, reviewerApprovedBy: 'someone' },
    53	        'ops_reviewer',
    54	      )).toThrow(BadRequestException);
    55	    });
    56	
    57	    it('FINANCE_APPROVED status rejects step 1', () => {
    58	      expect(() => validateStep1Approval(
    59	        { status: SettlementStatus.FINANCE_APPROVED, reviewerApprovedBy: 'someone' },
    60	        'ops_reviewer',
    61	      )).toThrow(BadRequestException);
    62	    });
    63	
    64	    it('REJECTED status rejects step 1', () => {
    65	      expect(() => validateStep1Approval(
    66	        { status: SettlementStatus.REJECTED, reviewerApprovedBy: null },
