    84	        .toThrow(ForbiddenException);
    85	    });
    86	
    87	    it('admin role is rejected — no bypass', () => {
    88	      expect(() => validateStep2Approval(reviewerApprovedSettlement(), 'admin-user-1', 'admin'))
    89	        .toThrow(ForbiddenException);
    90	    });
    91	
    92	    it('vendor role is rejected', () => {
    93	      expect(() => validateStep2Approval(reviewerApprovedSettlement(), 'vendor-user-1', 'vendor'))
    94	        .toThrow(ForbiddenException);
    95	    });
    96	  });
    97	
    98	  describe('state checks', () => {
    99	    it('REVIEWER_APPROVED status allows step 2', () => {
   100	      expect(() => validateStep2Approval(reviewerApprovedSettlement(), 'finance-user-1', 'finance_admin'))
   101	        .not.toThrow();
   102	    });
   103	
   104	    it('PENDING status rejects step 2 (step 1 not done)', () => {
   105	      expect(() => validateStep2Approval(
   106	        { status: SettlementStatus.PENDING, reviewerApprovedBy: null },
