 * export-dto-allowlist.test.ts
 *
 * Verifies that CreateExportJobDto enforces the backend's export type allowlist.
 * The allowed values are: listings, conversations, settlements, audit.
 *
 * 'users' was previously visible in the Query UI but is NOT in the allowlist —
 * submitting it must produce a validation error.
 */

import { validate } from 'class-validator';
import { plainToInstance } from 'class-transformer';
import { CreateExportJobDto } from '../backend/src/exports/dto/export.dto';

async function validateDto(type: string): Promise<string[]> {
  const dto = plainToInstance(CreateExportJobDto, { type });
  const errors = await validate(dto);
  return errors.flatMap((e) => Object.values(e.constraints ?? {}));
}

describe('CreateExportJobDto — type allowlist', () => {
  const ALLOWED = ['listings', 'conversations', 'settlements', 'audit'];
  const REJECTED = ['users', 'user', 'audit_logs', '', 'LISTINGS', 'admin', '../etc/passwd'];

  for (const type of ALLOWED) {
    it(`allows type="${type}"`, async () => {
      const errors = await validateDto(type);
      expect(errors).toHaveLength(0);
    });
  }

  for (const type of REJECTED) {
    it(`rejects type="${type}"`, async () => {
      const errors = await validateDto(type);
      expect(errors.length).toBeGreaterThan(0);
    });
  }

  it('"users" specifically is rejected (was erroneously present in the UI)', async () => {
    const errors = await validateDto('users');
    expect(errors.length).toBeGreaterThan(0);
    // class-validator @IsIn produces a message containing the field value
    expect(errors.some((msg) => msg.includes('type'))).toBe(true);
  });
});
"}

