import { User } from '../database/entities/user.entity';
import {
  RETENTION_BATCH_SIZE,
  ARCHIVE_REASON,
  retentionCutoff,
} from './audit-retention.policy';

export interface AuditLogInput {
  action: string;
  actorId: string;
  entityType: string;
  entityId?: string;
  before?: Record<string, unknown> | null;
  after?: Record<string, unknown> | null;
  deviceFingerprint?: string;
  ip?: string;
}

export interface RetentionRunResult {
  dryRun: boolean;
  processed: number;
  archived: number;
  cutoff: Date;
}

export interface AuditFilters {
  actorId?: string;
  entityType?: string;
  action?: string;
  startDate?: string;
  endDate?: string;
  keyword?: string;
  page?: number;
  limit?: number;
}

const RETENTION_INTERVAL_MS = 24 * 60 * 60 * 1000; // daily

@Injectable()
export class AuditService implements OnModuleInit, OnModuleDestroy {
  private retentionTimer: NodeJS.Timeout | null = null;

  constructor(
    @InjectRepository(AuditLog)
    private readonly auditRepo: Repository<AuditLog>,
    @InjectRepository(AuditArchivalRecord)
    private readonly archivalRepo: Repository<AuditArchivalRecord>,
  ) {}

  onModuleInit(): void {
    this.retentionTimer = setInterval(() => {
      this.runRetentionJob(false).catch(() => {
        // swallow — retention failures must not crash the service
      });
    }, RETENTION_INTERVAL_MS);
  }

  onModuleDestroy(): void {
    if (this.retentionTimer) {
      clearInterval(this.retentionTimer);
      this.retentionTimer = null;
    }
  }

  async log(input: AuditLogInput): Promise<AuditLog> {
    const latest = await this.auditRepo.findOne({
      where: {},
      order: { createdAt: 'DESC' },
    });

    const prevHash = latest?.hash ?? null;
    const ts = new Date().toISOString();
    const hashPayload = (prevHash ?? '') + JSON.stringify({
      action: input.action,
      actorId: input.actorId,
      entityType: input.entityType,
      entityId: input.entityId ?? null,
      before: input.before ?? null,
      after: input.after ?? null,
      ts,
    });
    const hash = crypto.createHash('sha256').update(hashPayload).digest('hex');

    const entry = this.auditRepo.create({
      action: input.action,
      actorId: input.actorId,
      entityType: input.entityType,
      entityId: input.entityId ?? null,
      before: input.before ?? null,
      after: input.after ?? null,
      deviceFingerprint: input.deviceFingerprint ?? null,
      ip: input.ip ?? null,
      hash,
      prevHash,
      createdAt: new Date(ts),
    });

    return this.auditRepo.save(entry);
  }

  async findAll(
    page = 1,
    limit = 50,
  ): Promise<{ items: AuditLog[]; total: number }> {
    const [items, total] = await this.auditRepo.findAndCount({
      order: { createdAt: 'DESC' },
      skip: (page - 1) * limit,
      take: limit,
    });
    return { items, total };
  }

  async findAllFiltered(
    filters: AuditFilters,
