 * credit.service.test.ts
 *
 * Tests for the credit scoring system covering:
 *  1. The pure formula (weights, clamping) — role-agnostic
 *  2. Vendor scoring path (settlement + listing based)
 *  3. Shopper scoring path (conversation based — no vendor-only fields)
 *  4. Edge cases: no activity, partial activity, disputed activity
 */

import { CreditsService, computeRawScore } from '../backend/src/credits/credits.service';
import { UserRole } from '../backend/src/database/entities/user.entity';
import { SettlementStatus } from '../backend/src/database/entities/settlement.entity';
import { ListingStatus } from '../backend/src/database/entities/listing.entity';

// ── Pure formula ──────────────────────────────────────────────────────────────

describe('computeRawScore — formula', () => {
  it('perfect vendor/shopper scores 500 (100% success, 0 dispute, 0 cancel)', () => {
    expect(computeRawScore(1.0, 0, 0)).toBe(500);
  });

  it('worst case clamps to 0', () => {
    expect(computeRawScore(0, 1.0, 1.0)).toBe(0);
  });

  it('applies 0.5/0.3/0.2 weights correctly', () => {
    const score = computeRawScore(0.8, 0.1, 0.05);
    const expected = Math.round((0.8 * 0.5 - 0.1 * 0.3 - 0.05 * 0.2) * 1000);
    expect(score).toBe(expected);
  });

  it('clamps above 1000', () => {
    expect(computeRawScore(3.0, 0, 0)).toBe(1000);
  });

  it('clamps below 0', () => {
    expect(computeRawScore(0, 2.0, 2.0)).toBe(0);
  });

  it('default score for no history is 1.0 success rate → 500', () => {
    expect(computeRawScore(1.0, 0, 0)).toBe(500);
  });

  it('mixed rates compute correctly', () => {
    const score = computeRawScore(0.92, 0.02, 0.06);
    const expected = Math.round((0.92 * 0.5 - 0.02 * 0.3 - 0.06 * 0.2) * 1000);
    expect(score).toBe(expected);
    expect(score).toBe(442);
  });
});

// ── Service stub helpers ──────────────────────────────────────────────────────

type MockQb = {
  where: jest.Mock;
  andWhere: jest.Mock;
  getCount: jest.Mock;
};

function makeQb(count: number): MockQb {
  const qb: any = {
    where: jest.fn().mockReturnThis(),
    andWhere: jest.fn().mockReturnThis(),
    getCount: jest.fn().mockResolvedValue(count),
  };
  return qb;
}

interface QbCounts {
  totalConvs?: number;
  disputedConvs?: number;
  successfulShopperConvs?: number;
  cancelledShopperConvs?: number;
}

function makeConvRepo(counts: QbCounts = {}) {
  const qbSequence = [
    makeQb(counts.totalConvs ?? 0),        // dispute: total (vendor or shopper)
    makeQb(counts.disputedConvs ?? 0),     // dispute: disputed
  ];

  let callIndex = 0;
  return {
    createQueryBuilder: jest.fn(() => qbSequence[callIndex++ % qbSequence.length]),
  };
}

/** Extended conv repo for shopper path (4 createQueryBuilder calls). */
function makeConvRepoShopper(
  totalShopperConvs: number,
  successfulShopperConvs: number,
  cancelledShopperConvs: number,
  totalConvsForDispute: number,
  disputedConvs: number,
) {
  const sequence = [
    makeQb(totalShopperConvs),
    makeQb(successfulShopperConvs),
    makeQb(cancelledShopperConvs),
    makeQb(totalConvsForDispute),
    makeQb(disputedConvs),
  ];
  let i = 0;
  return {
    createQueryBuilder: jest.fn(() => sequence[i++ % sequence.length]),
  };
}

function makeSettlementRepo(total: number, successful: number) {
  return {
    count: jest.fn()
      .mockResolvedValueOnce(total)       // totalSettlements
      .mockResolvedValueOnce(successful), // successfulSettlements
  };
}

function makeListingRepo(total: number, cancelled: number) {
  return {
    count: jest.fn()
      .mockResolvedValueOnce(total)     // totalListings
      .mockResolvedValueOnce(cancelled), // cancelledListings
  };
}

function makeCreditRepo(existing: any = null) {
  return {
    findOne: jest.fn()
      .mockResolvedValueOnce(null)   // getScore lookup (first call in computeScore flow)
      .mockResolvedValueOnce(existing), // existing score lookup
    create: jest.fn((e: any) => e),
    save: jest.fn((e: any) => Promise.resolve(e)),
  };
}

function makeUserRepo(role: UserRole = UserRole.VENDOR) {
  return {
    findOne: jest.fn(() =>
      Promise.resolve({ id: 'user-1', role }),
    ),
  };
}

function buildService(
  userRole: UserRole,
  settlements: { total: number; successful: number } = { total: 0, successful: 0 },
  listings: { total: number; cancelled: number } = { total: 0, cancelled: 0 },
  convCounts: {
    shopperTotal?: number;
    shopperSuccessful?: number;
    shopperCancelled?: number;
    disputeTotal?: number;
    disputed?: number;
  } = {},
) {
  const userRepo = makeUserRepo(userRole);
  const creditRepo = makeCreditRepo();
  const settlementRepo = makeSettlementRepo(settlements.total, settlements.successful);
  const listingRepo = makeListingRepo(listings.total, listings.cancelled);

  let convRepo: any;
  if (userRole === UserRole.SHOPPER) {
    convRepo = makeConvRepoShopper(
      convCounts.shopperTotal ?? 0,
      convCounts.shopperSuccessful ?? 0,
      convCounts.shopperCancelled ?? 0,
      convCounts.disputeTotal ?? 0,
      convCounts.disputed ?? 0,
    );
  } else {
    // vendor uses 2 createQueryBuilder calls for disputes
    convRepo = makeConvRepoShopper(
      0, 0, 0,
      convCounts.disputeTotal ?? 0,
      convCounts.disputed ?? 0,
    );
  }

  const svc = new CreditsService(
    creditRepo as any,
    settlementRepo as any,
    convRepo as any,
    listingRepo as any,
    userRepo as any,
  );

  return { svc, creditRepo };
}

// ── Vendor path ───────────────────────────────────────────────────────────────

describe('CreditsService.computeScore — vendor path', () => {
  it('vendor with perfect settlement record scores 500', async () => {
    const { svc, creditRepo } = buildService(
      UserRole.VENDOR,
      { total: 10, successful: 10 },   // 100% settlement success
      { total: 5, cancelled: 0 },       // 0 cancelled listings
      { disputeTotal: 10, disputed: 0 }, // 0 disputes
    );

    await svc.computeScore('user-1');

    const saved = (creditRepo.save as jest.Mock).mock.calls[0]?.[0];
    expect(saved.transactionSuccessRate).toBe(1.0);
    expect(saved.cancellationRate).toBe(0);
    expect(saved.disputeRate).toBe(0);
    expect(saved.score).toBe(500);
  });

  it('vendor with no settlements defaults to 100% success rate', async () => {
    const { svc, creditRepo } = buildService(
      UserRole.VENDOR,
      { total: 0, successful: 0 }, // no settlements → defaults to 1.0
      { total: 0, cancelled: 0 },
      { disputeTotal: 0, disputed: 0 },
    );

    await svc.computeScore('user-1');

    const saved = (creditRepo.save as jest.Mock).mock.calls[0]?.[0];
    expect(saved.transactionSuccessRate).toBe(1.0);
    expect(saved.score).toBe(500);
  });

  it('vendor with 50% settlement success and 20% dispute has lower score', async () => {
    const { svc, creditRepo } = buildService(
      UserRole.VENDOR,
      { total: 10, successful: 5 },   // 50% success
      { total: 0, cancelled: 0 },
      { disputeTotal: 10, disputed: 2 }, // 20% dispute
    );

    await svc.computeScore('user-1');

    const saved = (creditRepo.save as jest.Mock).mock.calls[0]?.[0];
    expect(saved.transactionSuccessRate).toBe(0.5);
    expect(saved.disputeRate).toBe(0.2);
    expect(saved.score).toBe(computeRawScore(0.5, 0.2, 0));
  });

  it('vendor cancellation rate based on archived listings', async () => {
    const { svc, creditRepo } = buildService(
      UserRole.VENDOR,
      { total: 5, successful: 5 },
      { total: 10, cancelled: 2 },  // 20% cancellation
      { disputeTotal: 0, disputed: 0 },
    );

    await svc.computeScore('user-1');

    const saved = (creditRepo.save as jest.Mock).mock.calls[0]?.[0];
    expect(saved.cancellationRate).toBeCloseTo(0.2);
    expect(saved.score).toBe(computeRawScore(1.0, 0, 0.2));
  });
});

// ── Shopper path ──────────────────────────────────────────────────────────────

describe('CreditsService.computeScore — shopper path (no vendor-only fields)', () => {
  it('shopper with all active non-disputed conversations scores 500', async () => {
    const { svc, creditRepo } = buildService(
      UserRole.SHOPPER,
      { total: 0, successful: 0 }, // vendor settlement data NOT used for shoppers
      { total: 0, cancelled: 0 },  // vendor listing data NOT used for shoppers
      {
        shopperTotal: 10,
        shopperSuccessful: 10, // all successful
        shopperCancelled: 0,
        disputeTotal: 10,
        disputed: 0,
      },
    );

    await svc.computeScore('user-1');

    const saved = (creditRepo.save as jest.Mock).mock.calls[0]?.[0];
    expect(saved.transactionSuccessRate).toBe(1.0);
    expect(saved.cancellationRate).toBe(0);
    expect(saved.disputeRate).toBe(0);
    expect(saved.score).toBe(500);
  });

  it('shopper with no conversation history defaults to max success', async () => {
    const { svc, creditRepo } = buildService(
      UserRole.SHOPPER,
      { total: 0, successful: 0 },
      { total: 0, cancelled: 0 },
      {
        shopperTotal: 0, // no conversations
        shopperSuccessful: 0,
        shopperCancelled: 0,
        disputeTotal: 0,
        disputed: 0,
      },
    );

    await svc.computeScore('user-1');

    const saved = (creditRepo.save as jest.Mock).mock.calls[0]?.[0];
    expect(saved.transactionSuccessRate).toBe(1.0);
    expect(saved.cancellationRate).toBe(0);
    expect(saved.disputeRate).toBe(0);
    expect(saved.score).toBe(500);
  });

  it('shopper with disputed conversations has reduced score', async () => {
    const { svc, creditRepo } = buildService(
      UserRole.SHOPPER,
      { total: 0, successful: 0 },
      { total: 0, cancelled: 0 },
      {
        shopperTotal: 10,
        shopperSuccessful: 8,
        shopperCancelled: 0,
        disputeTotal: 10,
        disputed: 2, // 20% dispute rate
      },
    );

    await svc.computeScore('user-1');

    const saved = (creditRepo.save as jest.Mock).mock.calls[0]?.[0];
    expect(saved.disputeRate).toBeCloseTo(0.2);
    expect(saved.score).toBeLessThan(500);
  });

  it('shopper score is independent of settlement counts', async () => {
    // Even if we inject positive settlement data, the shopper path ignores it.
    // The settlementRepo.count should NOT be called.
    const userRepo = makeUserRepo(UserRole.SHOPPER);
    const creditRepo = makeCreditRepo();
    const settlementRepoSpy = {
      count: jest.fn().mockResolvedValue(100), // would give max success if used
    };
    const listingRepoSpy = {
      count: jest.fn().mockResolvedValue(0),
    };
    const convRepo = makeConvRepoShopper(5, 5, 0, 5, 0);

    const svc = new CreditsService(
      creditRepo as any,
      settlementRepoSpy as any,
      convRepo as any,
      listingRepoSpy as any,
      userRepo as any,
    );

    await svc.computeScore('user-1');

    // Settlement and listing repos should NOT be queried for shoppers
    expect(settlementRepoSpy.count).not.toHaveBeenCalled();
    expect(listingRepoSpy.count).not.toHaveBeenCalled();
  });

  it('shopper cancellation rate uses archived conversations (not listings)', async () => {
    const { svc, creditRepo } = buildService(
      UserRole.SHOPPER,
      { total: 0, successful: 0 },
      { total: 0, cancelled: 0 },
      {
        shopperTotal: 10,
        shopperSuccessful: 6,
        shopperCancelled: 2, // 20% cancellation rate via archived convs
        disputeTotal: 10,
        disputed: 0,
      },
    );

    await svc.computeScore('user-1');

    const saved = (creditRepo.save as jest.Mock).mock.calls[0]?.[0];
    expect(saved.cancellationRate).toBeCloseTo(0.2);
    expect(saved.score).toBe(computeRawScore(saved.transactionSuccessRate, 0, 0.2));
  });
});

// ── Admin / ops_reviewer / finance_admin follow vendor path ───────────────────

describe('CreditsService.computeScore — admin uses vendor path', () => {
  it('admin role is treated as vendor (settlement-based scoring)', async () => {
    const userRepo = makeUserRepo(UserRole.ADMIN);
    const creditRepo = makeCreditRepo();
    const settlementRepo = makeSettlementRepo(4, 4);
    const listingRepo = makeListingRepo(0, 0);
    const convRepo = makeConvRepoShopper(0, 0, 0, 0, 0);

    const svc = new CreditsService(
      creditRepo as any,
      settlementRepo as any,
      convRepo as any,
      listingRepo as any,
      userRepo as any,
    );

    await svc.computeScore('admin-user-1');

    // Settlement count was queried (vendor path)
    expect(settlementRepo.count).toHaveBeenCalled();
  });
});
"}

