     2	 * voice-access.spec.ts
     3	 *
     4	 * Security regression tests for authenticated voice-file retrieval.
     5	 *
     6	 * Risk: voice media was previously served as public static files at
     7	 * /uploads/voice/<filename>, bypassing conversation-level authorization.
     8	 *
     9	 * These tests verify:
    10	 *   1. Unauthenticated requests are rejected (401).
    11	 *   2. Authenticated but non-participant users are rejected (403).
    12	 *   3. Conversation participants (shopper + vendor) are allowed (200).
    13	 *   4. Admin can access any voice file (200).
    14	 *   5. Direct static path /uploads/voice/* is blocked (401).
    15	 *   6. A voice message whose file is missing on disk returns 404 after auth passes.
    16	 *   7. Malformed / path-traversal file names are rejected (400).
    17	 */
    18	import * as fs from 'fs';
    19	import { join } from 'path';
    20	import * as request from 'supertest';
    21	import { createTestApp, makeToken, TestContext } from './test-utils';
    22	import { User } from '../database/entities/user.entity';
    23	import { Listing, ListingStatus } from '../database/entities/listing.entity';
    24	import { Conversation } from '../database/entities/conversation.entity';
    25	import { Message, MessageType } from '../database/entities/message.entity';
    26	import {
    27	  createTestUser,
    28	  createTestListing,
    29	  createTestConversation,
    30	  cleanupAll,
    31	} from './test-fixtures';
    32	
    33	describe('Voice file access control', () => {
    34	  let ctx: TestContext;
    35	
    36	  let vendorUser: User;
    37	  let shopperUser: User;
    38	  let outsiderUser: User;
    39	  let adminUser: User;
    40	
    41	  let listing: Listing;
    42	  let conversation: Conversation;
    43	  let voiceMsg: Message;
    44	  let orphanMsg: Message; // referenced in DB but no file on disk
    45	
    46	  const testFileName = `test-voice-${Date.now()}.ogg`;
    47	  const orphanFileName = `orphan-voice-${Date.now()}.ogg`;
    48	  const voiceDir = join(process.cwd(), 'uploads', 'voice');
    49	
    50	  beforeAll(async () => {
    51	    ctx = await createTestApp();
    52	    const ds = ctx.dataSource;
    53	
    54	    vendorUser  = await createTestUser(ds, 'vendor');
    55	    shopperUser = await createTestUser(ds, 'shopper');
    56	    outsiderUser = await createTestUser(ds, 'shopper');
    57	    adminUser   = await createTestUser(ds, 'admin');
    58	
    59	    listing      = await createTestListing(ds, vendorUser.id, ListingStatus.ACTIVE);
    60	    conversation = await createTestConversation(ds, listing.id, vendorUser.id, shopperUser.id);
    61	
    62	    const msgRepo = ds.getRepository(Message);
    63	
    64	    // Voice message that has an actual file on disk.
    65	    voiceMsg = await msgRepo.save(
    66	      msgRepo.create({
    67	        conversationId: conversation.id,
    68	        senderId: shopperUser.id,
    69	        type: MessageType.VOICE,
    70	        content: '',
    71	        audioUrl: `/api/conversations/voice/${testFileName}`,
    72	        isInternal: false,
    73	      }),
    74	    );
    75	
    76	    // Voice message whose file has been deleted / never created.
    77	    orphanMsg = await msgRepo.save(
    78	      msgRepo.create({
    79	        conversationId: conversation.id,
    80	        senderId: shopperUser.id,
    81	        type: MessageType.VOICE,
    82	        content: '',
    83	        audioUrl: `/api/conversations/voice/${orphanFileName}`,
    84	        isInternal: false,
    85	      }),
    86	    );
    87	
    88	    // Create the actual audio file for the participant / admin tests.
    89	    fs.mkdirSync(voiceDir, { recursive: true });
    90	    fs.writeFileSync(join(voiceDir, testFileName), Buffer.from('fake ogg audio data'));
    91	  }, 30000);
    92	
    93	  afterAll(async () => {
    94	    // Remove the test file we created.
    95	    try { fs.unlinkSync(join(voiceDir, testFileName)); } catch { /* ignored */ }
    96	
    97	    await cleanupAll(ctx.dataSource, [
    98	      { entity: Message,      ids: [voiceMsg?.id, orphanMsg?.id].filter(Boolean) as string[] },
    99	      { entity: Conversation, ids: [conversation?.id].filter(Boolean) as string[] },
   100	      { entity: Listing,      ids: [listing?.id].filter(Boolean) as string[] },
   101	      { entity: User,         ids: [vendorUser?.id, shopperUser?.id, outsiderUser?.id, adminUser?.id].filter(Boolean) as string[] },
   102	    ]);
   103	    await ctx.app.close();
   104	  });
   105	
   106	  // ── 1. Static route is blocked ───────────────────────────────────────────────
   107	
   108	  it('GET /uploads/voice/* is blocked without auth (401)', async () => {
   109	    const res = await request(ctx.app.getHttpServer())
   110	      .get(`/uploads/voice/${testFileName}`);
   111	    expect(res.status).toBe(401);
   112	  });
   113	
   114	  // ── 2. Unauthenticated on secure endpoint ────────────────────────────────────
   115	
   116	  it('unauthenticated request to secure endpoint returns 401', async () => {
   117	    const res = await request(ctx.app.getHttpServer())
   118	      .get(`/api/conversations/voice/${testFileName}`);
   119	    expect(res.body.code).toBe(401);
   120	  });
   121	
   122	  // ── 3. Non-participant denied ────────────────────────────────────────────────
   123	
   124	  it('outsider shopper (non-participant) receives 403', async () => {
   125	    const token = makeToken(ctx.jwtService, outsiderUser.id, 'shopper', outsiderUser.username);
   126	    const res = await request(ctx.app.getHttpServer())
   127	      .get(`/api/conversations/voice/${testFileName}`)
   128	      .set('Authorization', `Bearer ${token}`);
   129	    expect(res.body.code).toBe(403);
   130	  });
   131	
   132	  // ── 4. Participants allowed ──────────────────────────────────────────────────
   133	
   134	  it('shopper participant receives 200 and audio data', async () => {
   135	    const token = makeToken(ctx.jwtService, shopperUser.id, 'shopper', shopperUser.username);
   136	    const res = await request(ctx.app.getHttpServer())
   137	      .get(`/api/conversations/voice/${testFileName}`)
   138	      .set('Authorization', `Bearer ${token}`);
   139	    expect(res.status).toBe(200);
   140	    // Response body should be the file content, not a JSON envelope.
   141	    expect(Buffer.isBuffer(res.body) || res.body).toBeTruthy();
   142	  });
   143	
   144	  it('vendor participant receives 200 and audio data', async () => {
   145	    const token = makeToken(ctx.jwtService, vendorUser.id, 'vendor', vendorUser.username);
   146	    const res = await request(ctx.app.getHttpServer())
   147	      .get(`/api/conversations/voice/${testFileName}`)
   148	      .set('Authorization', `Bearer ${token}`);
   149	    expect(res.status).toBe(200);
   150	  });
   151	
   152	  // ── 5. Admin allowed ─────────────────────────────────────────────────────────
   153	
   154	  it('admin receives 200 and audio data', async () => {
   155	    const token = makeToken(ctx.jwtService, adminUser.id, 'admin', adminUser.username);
   156	    const res = await request(ctx.app.getHttpServer())
   157	      .get(`/api/conversations/voice/${testFileName}`)
   158	      .set('Authorization', `Bearer ${token}`);
   159	    expect(res.status).toBe(200);
   160	  });
   161	
   162	  // ── 6. Auth passes but file is missing on disk ───────────────────────────────
   163	
   164	  it('participant gets 404 when the file is missing on disk', async () => {
   165	    const token = makeToken(ctx.jwtService, shopperUser.id, 'shopper', shopperUser.username);
   166	    const res = await request(ctx.app.getHttpServer())
   167	      .get(`/api/conversations/voice/${orphanFileName}`)
   168	      .set('Authorization', `Bearer ${token}`);
   169	    // Auth passes; the file on disk is absent → 404 from sendFile callback.
   170	    expect(res.body.code).toBe(404);
   171	  });
   172	
   173	  // ── 7. Input validation ──────────────────────────────────────────────────────
   174	
   175	  it('path-traversal attempt (%2F) returns 400', async () => {
   176	    const token = makeToken(ctx.jwtService, shopperUser.id, 'shopper', shopperUser.username);
   177	    const res = await request(ctx.app.getHttpServer())
   178	      .get('/api/conversations/voice/..%2Fetc%2Fpasswd')
   179	      .set('Authorization', `Bearer ${token}`);
   180	    expect(res.body.code).toBe(400);
   181	  });
   182	
   183	  it('file name with disallowed characters returns 400', async () => {
   184	    const token = makeToken(ctx.jwtService, shopperUser.id, 'shopper', shopperUser.username);
   185	    const res = await request(ctx.app.getHttpServer())
   186	      .get('/api/conversations/voice/foo$bar.ogg')
   187	      .set('Authorization', `Bearer ${token}`);
   188	    expect(res.body.code).toBe(400);
   189	  });
   190	
   191	  // ── 8. Unknown file name ─────────────────────────────────────────────────────
   192	
   193	  it('participant requesting an unrecognised filename gets 404', async () => {
   194	    const token = makeToken(ctx.jwtService, shopperUser.id, 'shopper', shopperUser.username);
   195	    const res = await request(ctx.app.getHttpServer())
   196	      .get('/api/conversations/voice/no-such-file-ever.ogg')
   197	      .set('Authorization', `Bearer ${token}`);
   198	    // resolveVoiceFilePath throws NotFoundException (no matching message in DB).
   199	    expect(res.body.code).toBe(404);
   200	  });
   201	});
