  it('POST /query/execute — no token or invalid token → 401', async () => {
    await expectUnauthenticated('post', '/api/query/execute');
  });

  it('GET /query/saved — no token or invalid token → 401', async () => {
    await expectUnauthenticated('get', '/api/query/saved');
