37	export class ConversationsService {
38	  constructor(
39	    @InjectRepository(Conversation)
40	    private readonly convRepo: Repository<Conversation>,
41	    @InjectRepository(Message)
42	    private readonly msgRepo: Repository<Message>,
43	    @InjectRepository(Listing)
44	    private readonly listingRepo: Repository<Listing>,
45	    @InjectRepository(RateLimitEvent)
46	    private readonly rateLimitRepo: Repository<RateLimitEvent>,
47	    @InjectRepository(CannedResponse)
48	    private readonly cannedRepo: Repository<CannedResponse>,
49	    private readonly auditService: AuditService,
50	    private readonly riskService: RiskService,
51	  ) {}
52	
53	  async findAll(
54	    userId: string,
55	    role: string,
56	    filters: ConversationFiltersDto,
57	  ): Promise<ConversationSearchResult> {
58	    const page = Math.max(1, filters.page ?? 1);
59	    const limit = Math.min(SEARCH_MAX_LIMIT, Math.max(1, filters.limit ?? SEARCH_DEFAULT_LIMIT));
60	
61	    const qb = this.convRepo
62	      .createQueryBuilder('c')
63	      .leftJoinAndSelect('c.listing', 'listing');
64	
65	    if (role === 'vendor') {
66	      qb.where('c.vendorId = :userId', { userId });
67	    } else if (role === 'shopper') {
68	      qb.where(':userId = ANY(c.shopperIds)', { userId });
69	    }
70	
71	    if (filters.archived !== undefined) {
72	      qb.andWhere('c.isArchived = :archived', { archived: filters.archived });
73	    }
74	    if (filters.listingId) {
75	      qb.andWhere('c.listingId = :listingId', { listingId: filters.listingId });
76	    }
77	    if (filters.keyword) {
78	      // Primary: match any message content in the conversation.
79	      // Secondary: match the listing title.
80	      // EXISTS avoids row duplication and is evaluated per-conversation,
81	      // keeping join cardinality on the conversations table unchanged.
82	      const msgSubQuery = this.msgRepo
83	        .createQueryBuilder('m')
84	        .select('1')
85	        .where('m.conversationId = c.id')
86	        .andWhere('m.content ILIKE :kw');
87	
88	      qb.andWhere(
89	        `(listing.title ILIKE :kw OR EXISTS (${msgSubQuery.getQuery()}))`,
90	        { kw: `%${filters.keyword}%` },
91	      );
92	    }
93	    // Date-range filters target conversation.createdAt — see DTO for semantics.
94	    if (filters.startDate) {
95	      qb.andWhere('c.createdAt >= :startDate', { startDate: new Date(filters.startDate) });
96	    }
97	    if (filters.endDate) {
98	      qb.andWhere('c.createdAt <= :endDate', { endDate: new Date(filters.endDate) });
99	    }
100	
101	    // Secondary sort by id ensures deterministic ordering when createdAt ties.
102	    qb.orderBy('c.createdAt', 'DESC').addOrderBy('c.id', 'ASC');
103	    qb.skip((page - 1) * limit).take(limit);
104	
105	    const [items, total] = await qb.getManyAndCount();
106	
107	    return {
108	      items,
109	      total,
110	      page,
111	      limit,
112	      totalPages: Math.ceil(total / limit),
113	    };
114	  }
