2	 * conversation-search.test.ts
3	 *
4	 * Unit tests for ConversationsService.findAll() — keyword search and
5	 * date-range semantics.
6	 *
7	 * Keyword search contract:
8	 *   A conversation is returned when its keyword filter matches:
9	 *     - (primary)   any message whose content contains the keyword, OR
10	 *     - (secondary) the linked listing's title contains the keyword.
11	 *
12	 * Date-range contract:
13	 *   startDate / endDate always filter on conversation.createdAt.
14	 *   They are independent of message timestamps.
15	 */
16	
17	import { ConversationsService } from '../backend/src/conversations/conversations.service';
18	import { Repository } from 'typeorm';
19	
20	// ── Minimal entity stubs ───────────────────────────────────────────────────
21	
22	function conv(
23	  id: string,
24	  opts: {
25	    vendorId?: string;
26	    shopperIds?: string[];
27	    isArchived?: boolean;
28	    listingId?: string;
29	    createdAt?: Date;
30	  } = {},
31	) {
32	  return {
33	    id,
34	    vendorId: opts.vendorId ?? 'vendor-1',
35	    shopperIds: opts.shopperIds ?? ['shopper-1'],
36	    listingId: opts.listingId ?? 'listing-1',
37	    isArchived: opts.isArchived ?? false,
38	    createdAt: opts.createdAt ?? new Date('2024-06-01'),
39	    updatedAt: new Date(),
40	  };
41	}
