43	// ── QueryBuilder stub factory ──────────────────────────────────────────────
44	//
45	// Returns a chainable stub that captures filter predicates and evaluates them
46	// against an in-memory dataset when getManyAndCount() is called.
47	
48	interface Predicate {
49	  type: 'vendorId' | 'shopperIds' | 'archived' | 'listingId' | 'keyword' | 'startDate' | 'endDate';
50	  value: any;
51	}
52	
53	function makeConvQb(
54	  dataset: ReturnType<typeof conv>[],
55	  listing: { id: string; title: string },
56	  messages: { conversationId: string; content: string }[],
57	): any {
58	  const predicates: Predicate[] = [];
59	  let skipN = 0;
60	  let takeN = 1000;
61	
62	  const qb: any = {
63	    leftJoinAndSelect: () => qb,
64	    where: (_expr: string, params: any) => {
65	      if (_expr.includes('vendorId')) predicates.push({ type: 'vendorId', value: params.userId });
66	      if (_expr.includes('shopperIds')) predicates.push({ type: 'shopperIds', value: params.userId });
67	      return qb;
68	    },
69	    andWhere: (_expr: string, params: any = {}) => {
70	      if (_expr.includes('isArchived')) predicates.push({ type: 'archived', value: params.archived });
71	      if (_expr.includes('listingId')) predicates.push({ type: 'listingId', value: params.listingId });
72	      if (_expr.includes('listing.title ILIKE') || _expr.includes('EXISTS')) {
73	        predicates.push({ type: 'keyword', value: params.kw });
74	      }
75	      if (_expr.includes('c.createdAt >=')) predicates.push({ type: 'startDate', value: params.startDate });
76	      if (_expr.includes('c.createdAt <=')) predicates.push({ type: 'endDate', value: params.endDate });
77	      return qb;
78	    },
79	    orderBy: () => qb,
80	    addOrderBy: () => qb,
81	    skip: (n: number) => { skipN = n; return qb; },
82	    take: (n: number) => { takeN = n; return qb; },
83	    getManyAndCount: () => {
84	      let results = [...dataset];
85	
86	      for (const p of predicates) {
87	        switch (p.type) {
88	          case 'vendorId':
89	            results = results.filter(c => c.vendorId === p.value);
90	            break;
91	          case 'shopperIds':
92	            results = results.filter(c => c.shopperIds.includes(p.value));
93	            break;
94	          case 'archived':
95	            results = results.filter(c => c.isArchived === p.value);
96	            break;
97	          case 'listingId':
98	            results = results.filter(c => c.listingId === p.value);
99	            break;
100	          case 'keyword': {
101	            const kwLower = (p.value as string).toLowerCase().replace(/%/g, '');
102	            results = results.filter(c => {
103	              // Primary: message content match
104	              const msgMatch = messages.some(
105	                m => m.conversationId === c.id && m.content.toLowerCase().includes(kwLower),
106	              );
107	              // Secondary: listing title match
108	              const titleMatch = listing.title.toLowerCase().includes(kwLower);
109	              return msgMatch || (c.listingId === listing.id && titleMatch);
110	            });
111	            break;
112	          }
113	          case 'startDate':
114	            results = results.filter(c => c.createdAt >= p.value);
115	            break;
116	          case 'endDate':
117	            results = results.filter(c => c.createdAt <= p.value);
118	            break;
119	        }
120	      }
121	
122	      results.sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime());
123	      const paged = results.slice(skipN, skipN + takeN);
124	      return Promise.resolve([paged, results.length]);
125	    },
126	  };
127	  return qb;
128	}
