130	function makeMsgQb(): any {
131	  const qb: any = {
132	    select: () => qb,
133	    where: () => qb,
134	    andWhere: () => qb,
135	    getQuery: () => 'SELECT 1 FROM messages m WHERE m."conversationId" = c.id AND m.content ILIKE :kw',
136	  };
137	  return qb;
138	}
